phase1.code:
#include <iostream>

int main() {
    std::cout << "=== Pointers Explained ===" << std::endl;

    // 1. A variable stores a value
    int health = 100;
    std::cout << "health: " << health << std::endl;
    std::cout << "Address of health: " << &health << std::endl;

    // 2. A pointer stores an address
    int* healthPtr = &health;  // Pointer to health
    std::cout << "\nhealthPtr: " << healthPtr << std::endl;
    std::cout << "*healthPtr: " << *healthPtr << std::endl;  // Dereference

    // 3. Null pointer
    int* nullPtr = nullptr;
    std::cout << "\nnullPtr: " << nullPtr << std::endl;

    // 4. Pointer to pointer
    int** doublePtr = &healthPtr;
    std::cout << "\ndoublePtr: " << doublePtr << std::endl;
    std::cout << "*doublePtr: " << *doublePtr << std::endl;
    std::cout << "**doublePtr: " << **doublePtr << std::endl;

    // 5. Modifying through pointer
    std::cout << "\n=== Modifying through pointer ===" << std::endl;
    *healthPtr = 150;
    std::cout << "After *healthPtr = 150:" << std::endl;
    std::cout << "health: " << health << std::endl;
    std::cout << "*healthPtr: " << *healthPtr << std::endl;

    // 6. Pointer arithmetic (dangerous!)
    int arr[5] = {10, 20, 30, 40, 50};
    int* arrPtr = arr;  // Points to first element
    std::cout << "\n=== Pointer Arithmetic ===" << std::endl;
    std::cout << "arr[0]: " << *arrPtr << std::endl;
    std::cout << "arr[1]: " << *(arrPtr + 1) << std::endl;
    std::cout << "arr[2]: " << *(arrPtr + 2) << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

int main() {
    int* ptr = nullptr;

    // Dereferencing null pointer!
    std::cout << *ptr << std::endl;

    return 0;
}

phase2.explanation:
You dereferenced a null pointer! This is one of the most common C++ crashes.

**What's happening:**
1. `ptr` is `nullptr` (points to nothing)
2. `*ptr` tries to read the value at address 0
3. The OS says "That's not your memory!"
4. **CRASH!**

**The fix:**
```cpp
int* ptr = nullptr;
if (ptr != nullptr) {
    std::cout << *ptr << std::endl;  // Safe
} else {
    std::cout << "ptr is null!" << std::endl;
}
```

**PlusPlus-chan says:**
"Always check if a pointer is null before using it. This is the #1 C++ crash reason. Never trust a pointer."

phase3.solution:
#include <iostream>

int main() {
    int score = 50;
    int* scorePtr = &score;

    std::cout << "score: " << score << std::endl;
    std::cout << "scorePtr: " << scorePtr << std::endl;
    std::cout << "*scorePtr: " << *scorePtr << std::endl;

    *scorePtr = 100;
    std::cout << "After *scorePtr = 100, score: " << score << std::endl;

    int* nullPtr = nullptr;
    if (nullPtr == nullptr) {
        std::cout << "Pointer is null" << std::endl;
    }

    return 0;
}
